  infoByPath.emplace(countDef.fullPath, countInfo);

  primec::ir_lowerer::ReturnInfo atInfo;
  atInfo.returnsVoid = false;
  atInfo.returnsArray = false;
  atInfo.kind = primec::ir_lowerer::LocalInfo::ValueKind::Int64;
