  primec::ir_lowerer::LocalInfo info;
  info.kind = primec::ir_lowerer::LocalInfo::Kind::Reference;
  info.valueKind = primec::ir_lowerer::LocalInfo::ValueKind::Unknown;
  setReferenceArrayInfo(referenceArrayExpr, info);
